public class PalindromeRec {
    static boolean isPalin(String s, int lo, int hi) {
        if (lo >= hi) return true;
        if (s.charAt(lo) != s.charAt(hi)) return false;
        return isPalin(s, lo + 1, hi - 1);
    }
    public static void main(String[] args) {
        String[] words = {"racecar", "hello", "level", "a"};
        for (String w : words) {
            System.out.println(isPalin(w, 0, w.length()-1));
        }
    }
}
